%[text] ## Lab 3
%[text] ### Harmonic response of second-order rectilinear systems
%%
%[text] #### Harware parameters
T = 0.001;  % sampling time (change to fit your experiment)
Fs = 1/T;   % Sampling Frequency

r = 0.01; % pinion gear radius [m]

Kt = 0.028; % torque constant for the EMB-AM2 actuator [Nm/A]

motor_eff = 1.0; % system efficiency (change to match your plant)

Kt = Kt*motor_eff; % including efficiency, actual Kt used in Simulink
%[text] #### Simulation Parameters
k_sim = 0;
b_sim = 0;
%%
%[text] ### Experiment 1: Sine-Sweep Tests
S = 30;             % simulation duration time

t = 0:T:S;          % total time
y = zeros(size(t)); % output
    
t1 = t(end);

f0 = 1;
f1 = 20;

amp = 1.25;

y = amp .* chirp(t, f0, t1, f1);
plot(t, y) %[output:10c69ba9]

% Add labels and title to the plot
xlabel('Time (s)'); %[output:10c69ba9]
ylabel('Output Amplitude'); %[output:10c69ba9]
title('Chirp Signal Response'); %[output:10c69ba9]
grid on; %[output:10c69ba9]


sim_input = timeseries(y', t');

% Define parameters
model_name = 'MSE_PLANT';

% Load and configure for Real-Time / External mode
load_system(model_name);
set_param(model_name, 'SimulationMode', 'external');

set_param(model_name, 'StopTime', num2str(S));

% Execute
set_param(model_name,'SimulationCommand','start')
%%
%% PLOTTING - Input Force

plot(rt_time, f_input,'LineWidth',2); %[output:334a2eb2]
title('Input Force vs. Time'); %[output:334a2eb2]
xlabel('Time [s]'); %[output:334a2eb2]
ylabel('Force [N]'); %[output:334a2eb2]
legend('Input Force'); %[output:334a2eb2]
grid on; %[output:334a2eb2]

%% PLOTTING - Position for both Carts
plot(rt_time, cart1_position*100, rt_time, cart2_position*100,'LineWidth',2); %[output:1103a7b5]
title('Position vs. Time'); %[output:1103a7b5]
xlabel('Time [s]'); %[output:1103a7b5]
ylabel('Position [cm]'); %[output:1103a7b5]
legend('Cart1','Cart2'); %[output:1103a7b5]
grid on; %[output:1103a7b5]

% plot(f_input, cart1_position, 'LineWidth', 2);
% title('Force vs displacement');
% xlabel('Force (N)')
% ylabel('displacement')
% grid on;

plot(rt_time, cart1_velocity*100, rt_time, cart2_velocity*100, 'LineWidth', 2); %[output:174474c2]
title('Velocity vs Time'); %[output:174474c2]
xlabel('Time [s]') %[output:174474c2]
ylabel('Velocity [cm/s]') %[output:174474c2]
grid on; %[output:174474c2]

%[text] ### FFT
Y = fft(y);
L = length(y);
f = Fs*(0:(L/2))/L;                     % Frequency vector for plotting
Y_half = Y(1:L/2+1);                    % Single-sided spectrum %[output:472cca15]
Y_half(2:end-1) = 2*Y_half(2:end-1);    % Adjust amplitude for single-sided spectrum

plot(f, abs(Y_half)); %[output:3385ff04]
xlabel('Frequency (Hz)'); %[output:3385ff04]
ylabel('Magnitude'); %[output:3385ff04]
title('FFT of Chirp Signal'); %[output:3385ff04]
grid on; %[output:3385ff04]

xlim([f0 f1]) %[output:3385ff04]
ylim([0 2000]) %[output:3385ff04]

